module top_module(
   input         clock, write, reset,
   input [15:0]  writeData,
   output [15:0] data);reg [15:0]    inverted_out = 16'b0;

   always @ (posedge clock) begin 
      if (reset)
         inverted_out = 16'b0;
      else if (write)
         inverted_out = writeData;
   end

   assign data = inverted_out;
endmodule
